function methods = empty_method_array()
template = make_method('', '', [], '', '', false, '', '');
methods = repmat(template, 0, 1);
end

function m = make_method(name, displayName, solver, category, applicability, implemented, doc, status)
m.name = name;
m.displayName = displayName;
m.solver = solver;
m.category = category;
m.applicability = applicability;
m.implemented = implemented;
m.doc = doc;
m.status = status;
end